<script setup>import {computed} from 'vue';import {useRoute,useRouter} from 'vue-router';import {useAuthStore} from './stores';const route=useRoute(),router=useRouter(),auth=useAuthStore();const bare=computed(()=>route.meta.public);const menus=[['/dashboard','◫','运营概览'],['/users','◎','用户管理'],['/pets','◇','宠物管理'],['/families','⌂','家庭管理']];function logout(){auth.logout();router.push('/login');}</script>
<template><router-view v-if="bare"/><div v-else class="shell"><aside><div class="brand"><div class="brand-mark">P</div><div><b>PetCare</b><small>管理控制台</small></div></div><nav><router-link v-for="m in menus" :key="m[0]" :to="m[0]"><span>{{m[1]}}</span>{{m[2]}}</router-link></nav><div class="aside-foot"><span class="status-dot"></span>服务运行正常</div></aside><main><header><div><p>宠物健康助手</p><h1>{{route.meta.title}}</h1></div><el-dropdown><button class="profile"><span>{{auth.admin?.displayName?.slice(0,1)||'管'}}</span><div>{{auth.admin?.displayName||'管理员'}}<small>{{auth.admin?.username}}</small></div></button><template #dropdown><el-dropdown-menu><el-dropdown-item @click="logout">退出登录</el-dropdown-item></el-dropdown-menu></template></el-dropdown></header><section class="content"><router-view/></section></main></div></template>
